/**
 * @name User input flowing to Constructor.newInstance() via reflection
 * @description Reflection-based instantiation using user-controlled class enables arbitrary code execution
 * @kind path-problem
 * @problem.severity error
 * @id java/ff4j-reflection-newinstance
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ReflectionNewInstanceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Class.newInstance() on a dynamically-loaded class
    exists(MethodCall mc |
      mc.getMethod().hasName("newInstance") and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Constructor")
      ) and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module ReflectionNewInstanceFlow = TaintTracking::Global<ReflectionNewInstanceConfig>;
import ReflectionNewInstanceFlow::PathGraph

from ReflectionNewInstanceFlow::PathNode source, ReflectionNewInstanceFlow::PathNode sink
where ReflectionNewInstanceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to newInstance() via reflection from $@.", source.getNode(), "user input"

/**
 * @name User-controlled property type class name via REST API (CWE-470)
 * @description HTTP API accepts a property 'type' field as class name that flows to Class.forName()
 *              enabling arbitrary class loading and instantiation
 * @kind path-problem
 * @problem.severity error
 * @id java/ff4j-property-type-class-injection
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PropertyTypeClassInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    // PropertyApiBean.toProperty() / fromProperty() - type field to PropertyFactory
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.ff4j.web.api.resources.domain", "PropertyApiBean") and
      n1.asExpr() = mc.getAnArgument() and
      n2.asExpr() = mc
    )
  }
}

module PropertyTypeClassInjectionFlow = TaintTracking::Global<PropertyTypeClassInjectionConfig>;
import PropertyTypeClassInjectionFlow::PathGraph

from PropertyTypeClassInjectionFlow::PathNode source, PropertyTypeClassInjectionFlow::PathNode sink
where PropertyTypeClassInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled property type class name from $@ flows to Class.forName().", source.getNode(), "HTTP input"

