/**
 * @name HTTP request parameter flows to file upload/parse path
 * @description User-controlled file upload content parsed as ff4j configuration XML/YAML
 * @kind path-problem
 * @problem.severity error
 * @id java/ff4j-file-upload-config-parse
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module FileUploadParseConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ff4j XML parser parse calls
    exists(MethodCall mc |
      (mc.getMethod().hasName("parse") or mc.getMethod().hasName("parseConfiguration")) and
      mc.getMethod().getDeclaringType().getQualifiedName().matches("org.ff4j%") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // SnakeYAML load
    exists(MethodCall mc |
      mc.getMethod().hasName("load") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.yaml.snakeyaml", "Yaml") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module FileUploadParseFlow = TaintTracking::Global<FileUploadParseConfig>;
import FileUploadParseFlow::PathGraph

from FileUploadParseFlow::PathNode source, FileUploadParseFlow::PathNode sink
where FileUploadParseFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled content flows to configuration parser from $@.", source.getNode(), "user input"

