/**
 * @name User input flows to URLClassLoader - remote class loading
 * @description URLClassLoader with user-controlled URL enables loading malicious remote classes
 * @kind path-problem
 * @problem.severity error
 * @id java/ff4j-urlclassloader-injection
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module URLClassLoaderConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URLClassLoader") and
      sink.asExpr() = cie.getAnArgument()
    )
    or
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = cie.getAnArgument()
    )
  }
}

module URLClassLoaderFlow = TaintTracking::Global<URLClassLoaderConfig>;
import URLClassLoaderFlow::PathGraph

from URLClassLoaderFlow::PathNode source, URLClassLoaderFlow::PathNode sink
where URLClassLoaderFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to URLClassLoader or URL construction from $@.", source.getNode(), "user input"
